def test_find_and_glob_reach_hidden_entries_only_with_all(fs: Storix):
    fs.echo(b'x', '/.env')
    fs.mkdir('/.git')
    fs.echo(b'x', '/.git/config')

    # excluded by default (and hidden directories are not descended)
    assert [e.name for e in fs.find(name='.env')] == []
    assert list(fs.glob('**/config')) == []
    # all=True reaches the dotfile and descends the hidden directory
    assert [e.name for e in fs.find(name='.env', all=True)] == ['.env']
    assert [str(p) for p in fs.glob('**/config', all=True)] == ['/.git/config']


def test_glob_matches_direct_children_recursive_and_subdirs(fs: Storix):
    _nested_tree(fs)

    direct = {str(p) for p in fs.glob('*.py', '/pkg')}
    recursive = {str(p) for p in fs.glob('**/*.py', '/pkg')}
    subdir = {str(p) for p in fs.glob('sub/*', '/pkg')}

    assert direct == {'/pkg/mod.py'}  # '*' stops at a separator
    assert recursive == {'/pkg/mod.py', '/pkg/sub/deep.py'}  # '**' spans depth
    assert subdir == {'/pkg/sub/deep.py'}


